const amqp = require('amqplib');
const crypto = require('crypto');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.PAYMENT_QUEUE || 'payment_events';
const SECRET_TOKEN = process.env.SECRET_TOKEN || crypto.randomBytes(32).toString('hex');

async function connectToRabbitMQ() {
  try {
    const connection = await amqp.connect(RABBITMQ_URL);
    const channel = await connection.createChannel();
    await channel.assertQueue(QUEUE_NAME, { durable: true });
    return { connection, channel };
  } catch (error) {
    console.error('Failed to connect to RabbitMQ:', error);
    process.exit(1);
  }
}

function validatePaymentData(data) {
  if (!data || typeof data !== 'object') return false;
  
  const requiredFields = ['paymentId', 'amount', 'currency', 'customerId'];
  for (const field of requiredFields) {
    if (!(field in data) || data[field] === null || data[field] === undefined) {
      return false;
    }
  }
  
  if (typeof data.amount !== 'number' || data.amount <= 0) return false;
  if (typeof data.currency !== 'string' || data.currency.length !== 3) return false;
  if (typeof data.customerId !== 'string' || data.customerId.length === 0) return false;
  
  return true;
}

async function processPayment(paymentData) {
  try {
    if (!validatePaymentData(paymentData)) {
      throw new Error('Invalid payment data');
    }
    
    console.log('Processing payment:', paymentData.paymentId);
    
    const paymentId = paymentData.paymentId;
    const amount = paymentData.amount;
    const currency = paymentData.currency;
    const customerId = paymentData.customerId;
    
    const paymentResult = {
      paymentId,
      status: 'completed',
      amount,
      currency,
      customerId,
      processedAt: new Date().toISOString()
    };
    
    console.log('Payment processed successfully:', paymentResult);
    
    return paymentResult;
  } catch (error) {
    console.error('Payment processing failed:', error.message);
    throw error;
  }
}

async function consumePayments() {
  const { channel } = await connectToRabbitMQ();
  
  channel.prefetch(1);
  
  channel.consume(QUEUE_NAME, async (msg) => {
    if (msg !== null) {
      try {
        const messageContent = msg.content.toString();
        const paymentData = JSON.parse(messageContent);
        
        await processPayment(paymentData);
        
        channel.ack(msg);
        console.log('Message processed and acknowledged');
      } catch (error) {
        console.error('Error processing message:', error);
        channel.nack(msg, false, false);
      }
    }
  }, { noAck: false });
  
  console.log('Waiting for payment messages...');
}

consumePayments().catch(console.error);